<template>
  <section
    id="film"
    ref="root"
    class="gs"
    :class="{ 'gs--reduced': reduced }"
    aria-label="Apple Glass Aura — scroll to explore"
  >
    <div ref="stage" class="gs__stage">
      <!-- ambient light that ignites with the lenses -->
      <div
        class="gs__aura"
        :style="{ opacity: 0.15 + glow * 0.85, transform: `scale(${0.8 + glow * 0.5})`, background: auraBg }"
        aria-hidden="true"
      />

      <div class="gs__device" :style="deviceStyle">
        <AuraGlasses :finish="finish" :lens-tint="tint" :glow="glow" :hud="hud" :size="560" />
      </div>

      <!-- cross-fading captions -->
      <div class="gs__captions" aria-hidden="true">
        <div
          v-for="(s, i) in SHOWCASE"
          :key="i"
          class="gs__caption"
          :style="{ opacity: captionOpacity(s.at), transform: `translateY(${(1 - captionOpacity(s.at)) * 14}px)` }"
        >
          <h2 class="gs__caption-title">{{ s.title }}</h2>
          <p class="gs__caption-sub">{{ s.sub }}</p>
        </div>
      </div>

      <!-- progress rail -->
      <div class="gs__rail" aria-hidden="true">
        <span class="gs__rail-fill" :style="{ height: (p * 100) + '%' }" />
      </div>
    </div>

    <!-- Static fallback list for reduced motion -->
    <ul v-if="reduced" class="gs__static">
      <li v-for="(s, i) in SHOWCASE" :key="i">
        <strong>{{ s.title }}</strong><span>{{ s.sub }}</span>
      </li>
    </ul>
  </section>
</template>

<script>
import gsap from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'
import AuraGlasses from './AuraGlasses.vue'
import { FINISHES, TINTS, SHOWCASE } from '../../data/product'

gsap.registerPlugin(ScrollTrigger)

/** Piecewise-linear interpolation over [[pos, value], ...] (pos ascending). */
function kf(t, pts) {
  if (t <= pts[0][0]) return pts[0][1]
  const last = pts[pts.length - 1]
  if (t >= last[0]) return last[1]
  for (let i = 1; i < pts.length; i++) {
    const [p1, v1] = pts[i]
    if (t <= p1) {
      const [p0, v0] = pts[i - 1]
      const f = (t - p0) / (p1 - p0)
      return v0 + (v1 - v0) * f
    }
  }
  return last[1]
}

export default {
  name: 'GlassesShowcase',
  components: { AuraGlasses },
  data() {
    return {
      SHOWCASE,
      finish: FINISHES[0],
      tint: TINTS[0],
      p: 0,
      reduced: false,
      st: null,
    }
  },
  computed: {
    scale() {
      return kf(this.p, [[0, 0.6], [0.14, 1], [0.5, 1], [0.66, 2.15], [0.78, 2.15], [0.95, 1.12], [1, 1.12]])
    },
    rotateY() {
      return kf(this.p, [[0, 22], [0.14, 22], [0.32, -26], [0.5, -7], [0.62, 0], [1, 0]])
    },
    rotateZ() {
      return kf(this.p, [[0, -6], [0.14, 0], [1, 0]])
    },
    shiftX() {
      // focus the right lens during the zoom
      return kf(this.p, [[0.5, 0], [0.66, -16], [0.78, -16], [0.92, 0], [1, 0]])
    },
    shiftY() {
      return kf(this.p, [[0.5, 0], [0.66, 6], [0.78, 6], [0.92, 0]])
    },
    glow() {
      return kf(this.p, [[0, 0], [0.36, 0], [0.52, 1], [1, 1]])
    },
    hud() {
      return kf(this.p, [[0, 0], [0.58, 0], [0.72, 1], [1, 1]])
    },
    deviceStyle() {
      return {
        transform: `translate(${this.shiftX}%, ${this.shiftY}%) scale(${this.scale}) rotateX(8deg) rotateY(${this.rotateY}deg) rotateZ(${this.rotateZ}deg)`,
      }
    },
    auraBg() {
      const a = this.finish.accent
      return `radial-gradient(circle at 50% 50%, ${a}, ${a}55 30%, transparent 65%)`
    },
  },
  mounted() {
    this.reduced = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches
    if (this.reduced) {
      this.p = 1
      return
    }
    this.st = ScrollTrigger.create({
      trigger: this.$refs.root,
      start: 'top top',
      end: '+=2800',
      pin: this.$refs.stage,
      scrub: 0.6,
      onUpdate: (self) => {
        this.p = self.progress
      },
    })
    // ensure correct measurement once mounted into the page
    requestAnimationFrame(() => ScrollTrigger.refresh())
  },
  beforeUnmount() {
    if (this.st) this.st.kill()
  },
  methods: {
    /** Bell-curve opacity so each caption peaks at its scroll position. */
    captionOpacity(at) {
      if (this.reduced) return 1
      const win = 0.11
      const d = Math.abs(this.p - at)
      return Math.max(0, 1 - d / win)
    },
  },
}
</script>

