<template>
  <component :is="tag" ref="root" class="reveal" :class="{ 'reveal--in': shown }" :style="{ '--delay': delay + 'ms' }">
    <slot />
  </component>
</template>

<script>
export default {
  name: 'RevealOnScroll',
  props: {
    tag: { type: String, default: 'div' },
    delay: { type: Number, default: 0 },
  },
  data() {
    return { shown: false, observer: null }
  },
  mounted() {
    const reduce = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches
    if (reduce) {
      this.shown = true
      return
    }
    this.observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting) {
          this.shown = true
          this.observer.disconnect()
        }
      },
      { threshold: 0.18, rootMargin: '0px 0px -8% 0px' }
    )
    this.observer.observe(this.$refs.root)
  },
  beforeUnmount() {
    if (this.observer) this.observer.disconnect()
  },
}
</script>

<style scoped>
.reveal {
  opacity: 0;
  transform: translateY(34px);
  transition: opacity 0.9s cubic-bezier(0.22, 1, 0.36, 1) var(--delay),
    transform 0.9s cubic-bezier(0.22, 1, 0.36, 1) var(--delay);
  will-change: opacity, transform;
}
.reveal--in {
  opacity: 1;
  transform: none;
}
</style>
