<script>
import ProductNav from '../components/product/ProductNav.vue'
import ProductHero from '../components/product/ProductHero.vue'
import GlassesShowcase from '../components/product/GlassesShowcase.vue'
import GlassesCustomizer from '../components/product/GlassesCustomizer.vue'
import SpecsGrid from '../components/product/SpecsGrid.vue'
import ProductFooter from '../components/product/ProductFooter.vue'
import RevealOnScroll from '../components/product/RevealOnScroll.vue'
import { FEATURES, METRICS } from '../data/product'

export default {
  name: 'ProductView',
  components: {
    ProductNav,
    ProductHero,
    GlassesShowcase,
    GlassesCustomizer,
    SpecsGrid,
    ProductFooter,
    RevealOnScroll,
  },
  data() {
    return { FEATURES, METRICS }
  },
  methods: {
    barH(n) {
      // deterministic pseudo-random bar height for the equalizer
      const v = Math.abs(Math.sin(n * 1.7) * 0.6 + Math.cos(n * 0.9) * 0.4)
      return 18 + v * 64 + '%'
    },
  },
}
